/**
 * Apple Root CA - G3 (DER, base64-encoded).
 *
 * App Store Server Notifications V2 and the App Store Server API sign their
 * payloads with a certificate chain that anchors to this root. We bundle it
 * here so `SignedDataVerifier` can validate the x5c chain offline — without a
 * trusted root the signature check is meaningless (anyone could forge a
 * "user is premium" notification).
 *
 * Source: https://www.apple.com/certificateauthority/AppleRootCA-G3.cer
 */
const APPLE_ROOT_CA_G3_B64 =
  "";

/** Apple root certificates (DER buffers) for chain validation. */
export function getAppleRootCertificates(): Buffer[] {
  return [Buffer.from(APPLE_ROOT_CA_G3_B64, "base64")];
}
